+fileprivate func isPlaceholderMenuTitle(_ title: String) -> Bool {
+    guard let sanitized = sanitizedMenuText(title) else { return true }
+    let lower = sanitized.lowercased()
+    if lower == "unknown" || lower == "item" || lower == "menu item" {
+        return true
+    }
